                {isFiltered && (
                  <span className="px-1.5 py-0.5 bg-cyan-500/20 text-cyan-300 text-[10px] font-bold rounded border border-cyan-500/30">
                    FILTERED
                  </span>
                )}
              </div>
            </div>
          );
        }}
      />
    </div>
  );
};

