                  {column.header}
                </div>
                <div className="flex items-center gap-1 mt-0.5">
                  {sortDirection && (
                    <span className={`text-[10px] ${scheme.badge.replace('bg-', 'text-')} font-semibold`}>
                      {sortDirection.toUpperCase()}
                    </span>
                  )}
                  {isFiltered && (
                    <span className="text-[10px] text-cyan-400 font-semibold">
