          inactive: 'bg-gray-100 text-gray-800',
        };
        return (
          <span className={`px-2 py-1 rounded-full text-xs font-semibold ${colors[row.status]}`}>
            {row.status.toUpperCase()}
          </span>
        );
      }
    },
    {
      id: 'priority',
      key: 'priority',
      header: 'Priority',
      width: 150,
    },
    { id: 'assignee', key: 'assignee', header: 'Assignee', width: 150 },
  ];

  return (
