        </p>
      </div>
      <div style={{ height: '600px' }}>
        <DataGrid
          columns={customColumns}
          data={products}
          enableFiltering={true}
          enableColumnMenu={true}
          filterState={filterState}
          onFilterChange={setFilterState}
          enableSorting={true}
          rowHeight={60}
        />
